function icon(name: string): IconComponent { return iconMap[name] ?? Package; }
function serviceImageFor(service: Service): string { const key = `${service.slug} ${service.title} ${service.icon}`.toLowerCase(); const matched = Object.entries(serviceImageMap).find(([term]) => key.includes(term)); return service.image_url || matched?.[1] || "/images/service-warehousing.jpg"; }
function titleOf(record: EditableRecord | Inquiry): string { if ("title" in record) return record.title; if ("full_name" in record) return record.full_name; if ("client_name" in record) return record.client_name; if ("label" in record) return record.label; return "Untitled"; }
function descOf(record: EditableRecord | Inquiry): string { if ("short_description" in record) return record.short_description; if ("excerpt" in record) return record.excerpt; if ("quote" in record) return record.quote; if ("bio" in record) return record.bio; if ("message" in record) return record.message; if ("value" in record) return record.value; return "Workspace page"; }

function Header({ mode, settings }: { mode: ViewMode; settings: Record<string, string> }) {
  const [open, setOpen] = useState(false);
  const nav = ["Home", "About", "Services", "News", "Contact"];
  const linkFor = (item: string) => {
    const hash = item === "Home" ? "#home" : `#${item.toLowerCase()}`;
    return mode === "admin" ? `/${hash}` : hash;
  };
  return (
    <header className="sticky top-0 z-50 bg-white shadow-[0_2px_18px_rgba(0,0,0,0.09)]">
      <div className="hidden bg-[#0f2f57] text-white md:block"><div className="mx-auto flex min-h-10 max-w-7xl items-center justify-between px-4 text-xs font-semibold sm:px-6 lg:px-8"><span className="flex gap-5"><span className="inline-flex items-center gap-2"><Phone className="h-3.5 w-3.5 text-[#f6a800]" />{settings.phone}</span><span className="inline-flex items-center gap-2"><Mail className="h-3.5 w-3.5 text-[#f6a800]" />{settings.email}</span></span><span className="inline-flex items-center gap-2"><MapPin className="h-3.5 w-3.5 text-[#f6a800]" />{settings.address}</span></div></div>
      <div className="mx-auto flex min-h-[82px] max-w-7xl items-center justify-between px-4 sm:px-6 lg:px-8">
        <a href={mode === "admin" ? "/#home" : "#home"} className="flex items-center gap-3" aria-label="Galilea Global Logistics home"><img src="/logo.jpeg" alt="Galilea Global Logistics logo" className="h-14 w-14 rounded-md object-cover shadow-sm" /><span><span className="block text-[1.35rem] font-black tracking-tight text-[#123b68]">Galilea</span><span className="block text-[0.72rem] font-black tracking-[0.16em] text-[#f6a800]">Global Logistics</span></span></a>
        <nav className="hidden items-center gap-7 lg:flex" aria-label="Primary navigation">{nav.map((item) => <a key={item} href={linkFor(item)} className="text-sm font-extrabold capitalize tracking-wide text-[#123b68] hover:text-[#f6a800] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#f6a800]">{item}</a>)}</nav>
        <div className="hidden items-center gap-3 lg:flex"><a href={mode === "admin" ? "/#contact" : "#contact"} className="inline-flex min-h-11 items-center gap-2 rounded-md bg-[#f6a800] px-5 text-sm font-black capitalize text-[#123b68] hover:bg-[#ffc33d]">Get a Quote <ArrowRight className="h-4 w-4" /></a></div>
        <button type="button" onClick={() => setOpen(!open)} className="flex h-11 w-11 items-center justify-center rounded-md border border-slate-200 text-[#123b68] lg:hidden" aria-label="Toggle navigation">{open ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}</button>
      </div>
      {open ? <div className="border-t border-slate-200 bg-white px-4 py-4 lg:hidden"><div className="flex flex-col gap-2">{nav.map((item) => <a key={item} href={linkFor(item)} onClick={() => setOpen(false)} className="rounded-md px-4 py-3 text-base font-black capitalize text-[#123b68] hover:bg-[#fff4d6]">{item}</a>)}</div></div> : null}
    </header>
  );
}

