function TrackingCard() {
  const [reference, setReference] = useState("");
  const [status, setStatus] = useState<TrackingStatus>("idle");
  const [result, setResult] = useState<ShipmentTrackingResponse | null>(null);
  const [error, setError] = useState("");
  const stages = result?.stages ?? [
    { label: "Documents Checked", description: "Shipment paperwork is reviewed by the operations team.", completed: false, timestamp: null },
    { label: "Customs Clearance", description: "Clearance status appears after a valid shipment reference is found.", completed: false, timestamp: null },
    { label: "Transit Coordination", description: "Transport movement updates are shown live from the shipment desk.", completed: false, timestamp: null },
    { label: "Final Delivery", description: "Delivery confirmation appears when the last-mile handover is scheduled.", completed: false, timestamp: null },
  ];
  async function submit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const cleanedReference = reference.trim();
    if (!cleanedReference) return;
    setStatus("loading");
    setError("");
    try {
      const shipment = await shipmentApi.track(cleanedReference);
      setResult(shipment);
      setStatus("success");
    } catch (trackingError) {
      setResult(null);
      setError(trackingError instanceof Error ? trackingError.message : "Shipment reference was not found.");
      setStatus("error");
    }
  }
  return <div className="rounded-md border-t-8 border-[#f6a800] bg-white p-6 text-[#123b68] shadow-2xl lg:ml-auto lg:max-w-md"><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">Track your cargo</p><h2 className="mt-2 text-3xl font-black capitalize">Shipment desk</h2><p className="mt-2 text-sm leading-6 text-slate-600">Enter your reference number to view live shipment stages from the Galilea operations desk.</p><form onSubmit={submit} className="mt-5 rounded-md border border-slate-200 bg-slate-50 p-3"><label htmlFor="tracking-reference" className="block text-sm font-black capitalize text-[#123b68]">Reference number</label><div className="mt-2 flex flex-col gap-2 sm:flex-row"><div className="relative min-w-0 flex-1"><Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" /><input id="tracking-reference" value={reference} onChange={(event) => { setReference(event.target.value); setError(""); }} placeholder="e.g. GGL-2026-1048" className="h-12 w-full rounded-md border border-slate-300 bg-white pl-10 pr-3 text-sm font-bold text-[#123b68] outline-none transition focus:border-[#f6a800] focus:ring-2 focus:ring-[#f6a800]/40" required /></div><Button disabled={status === "loading"} className="h-12 rounded-md bg-[#123b68] px-5 font-black capitalize text-white hover:bg-[#0f2f57] disabled:opacity-70">{status === "loading" ? "Tracking" : "Track"}</Button></div>{status === "success" && result ? <div className="mt-3 rounded-md bg-[#fff4d6] px-3 py-2 text-sm font-bold text-[#123b68]"><p>{result.reference_number} • {result.status}</p><p className="mt-1 text-xs font-semibold text-slate-600">{result.route}</p></div> : null}{status === "error" ? <p className="mt-3 rounded-md bg-red-50 px-3 py-2 text-sm font-bold text-red-700">{error}</p> : null}</form><div className="mt-6 space-y-3" aria-label="Shipment activity timeline">{stages.map((step, i) => { const state = step.completed ? "Completed" : step.timestamp ? "Current" : "Pending"; return <div key={`${step.label}-${i}`} className={`flex items-start gap-3 rounded-md border p-4 ${step.completed ? "border-emerald-200 bg-emerald-50" : state === "Current" ? "border-[#f6a800] bg-[#fff4d6]" : "border-slate-200 bg-slate-50"}`}><span className={`flex h-10 w-10 shrink-0 items-center justify-center rounded-md text-sm font-black ${step.completed ? "bg-emerald-600 text-white" : state === "Current" ? "bg-[#f6a800] text-[#123b68]" : "bg-slate-200 text-slate-500"}`}>{i + 1}</span><span className="min-w-0 flex-1"><span className="flex flex-wrap items-center gap-2"><span className="font-black text-[#123b68]">{step.label}</span><span className={`rounded-full px-2 py-0.5 text-[0.68rem] font-black uppercase tracking-wide ${step.completed ? "bg-emerald-100 text-emerald-800" : state === "Current" ? "bg-white text-[#123b68]" : "bg-slate-100 text-slate-500"}`}>{state}</span></span><span className="mt-1 block text-xs leading-5 text-slate-600">{step.description}</span>{step.timestamp ? <time className="mt-1 block text-xs font-bold text-slate-500">{step.timestamp}</time> : null}</span><CheckCircle2 className={`h-5 w-5 shrink-0 ${step.completed ? "text-emerald-600" : state === "Current" ? "text-[#f6a800]" : "text-slate-300"}`} /></div>; })}</div></div>;
}

function SectionTitle({ eyebrow, title, description, light = false }: { eyebrow: string; title: string; description: string; light?: boolean }) { return <div className="mx-auto max-w-3xl text-center"><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">{eyebrow}</p><h2 className={`mt-3 text-4xl font-black capitalize tracking-tight sm:text-5xl ${light ? "text-white" : "text-[#123b68]"}`}>{title}</h2><div className="mx-auto mt-4 h-1.5 w-24 rounded-full bg-[#f6a800]" /><p className={`mt-5 text-base leading-8 ${light ? "text-slate-200" : "text-slate-600"}`}>{description}</p></div>; }

function Services({ services }: { services: Service[] }) { return <section id="services" className="bg-[#f5f7fa] px-4 py-16 sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto max-w-7xl"><SectionTitle eyebrow="What we offer" title="Our logistics services" description="A complete service desk for importers, exporters, NGOs, manufacturers and trading companies moving cargo across borders." /><div className="mt-10 grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4">{services.map((service) => { const Icon = icon(service.icon); return <article key={service.id} className="group overflow-hidden rounded-md border-t-4 border-[#f6a800] bg-white shadow-[0_12px_35px_rgba(18,59,104,0.10)] transition hover:-translate-y-1"><div className="relative h-44 bg-[#123b68]"><img src={serviceImageFor(service)} alt={`${service.title} logistics service`} className="h-full w-full object-cover transition duration-300 group-hover:scale-[1.03]" /><div className="absolute inset-0 bg-gradient-to-t from-[#123b68]/75 to-transparent" aria-hidden="true" /><div className="absolute bottom-4 left-4 flex h-14 w-14 items-center justify-center rounded-md bg-[#f6a800] text-[#123b68]"><Icon className="h-7 w-7" /></div></div><div className="p-6"><h3 className="text-2xl font-black capitalize text-[#123b68]">{service.title}</h3><p className="mt-3 text-base font-semibold leading-7 text-slate-700">{service.short_description}</p><p className="mt-3 text-sm leading-7 text-slate-500">{service.description}</p></div></article>; })}</div></div></section>; }

function About({ team }: { team: TeamMember[] }) { return <section id="about" className="bg-white px-4 py-16 sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto grid max-w-7xl gap-10 lg:grid-cols-[0.95fr_1.05fr] lg:items-center"><div className="relative min-h-[430px] overflow-hidden rounded-md bg-[#123b68] shadow-2xl"><div className="absolute inset-0 bg-cover bg-center opacity-75" style={aboutStyle} /><div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-[#0f2f57] to-transparent p-8 text-white"><p className="text-sm font-black capitalize tracking-[0.16em] text-[#ffd56f]">About Galilea</p><h2 className="mt-2 text-3xl font-black capitalize">Connecting cargo, people and markets.</h2></div></div><div><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">Who we are</p><h2 className="mt-3 text-4xl font-black capitalize leading-tight text-[#123b68]">A trusted logistics partner in Rwanda.</h2><p className="mt-5 text-base leading-8 text-slate-600">Galilea Global Logistics delivers practical freight forwarding, customs brokerage, cargo consolidation, warehousing and transportation support. The dynamic website content is powered by the backend and managed through the admin dashboard.</p><div className="mt-8 grid grid-cols-1 gap-4 sm:grid-cols-3">{[["10+", "Years experience"], ["24/7", "Operations support"], ["100%", "Compliance focused"]].map(([value, label]) => <div key={label} className="rounded-md border-l-4 border-[#f6a800] bg-[#f5f7fa] p-5"><p className="text-3xl font-black text-[#123b68]">{value}</p><p className="mt-1 text-sm font-bold capitalize text-slate-500">{label}</p></div>)}</div></div></div>{team.length ? <div className="mx-auto mt-14 max-w-7xl"><h3 className="text-2xl font-black capitalize text-[#123b68]">Leadership team</h3><div className="mt-5 grid gap-5 md:grid-cols-3">{team.slice(0, 3).map((member) => <article key={member.id} className="rounded-md border border-slate-200 bg-white p-6 shadow-sm"><div className="flex h-14 w-14 items-center justify-center rounded-md bg-[#f6a800] text-lg font-black text-[#123b68]">{member.full_name.split(" ").slice(0, 2).map((part) => part[0]).join("")}</div><h4 className="mt-4 text-lg font-black text-[#123b68]">{member.full_name}</h4><p className="mt-1 text-sm font-black capitalize text-[#f6a800]">{member.role}</p><p className="mt-3 text-sm leading-6 text-slate-600">{member.bio}</p></article>)}</div></div> : null}</section>; }

function WhyChoose() { const items = [{ icon: ShieldCheck, title: "Customs compliance", text: "Documentation, declarations and clearance support handled with care." }, { icon: Globe2, title: "Global network", text: "Regional and international routing options for air, sea and road cargo." }, { icon: FileText, title: "Clear reporting", text: "Status updates and practical advice from a dedicated operating desk." }]; return <section className="bg-[#123b68] px-4 py-16 text-white sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto max-w-7xl"><SectionTitle eyebrow="Why choose us" title="Reliable, efficient, accountable" description="We combine hands-on local expertise with disciplined shipment coordination." light /><div className="mt-10 grid gap-5 md:grid-cols-3">{items.map((item) => { const Icon = item.icon; return <article key={item.title} className="rounded-md border border-white/15 bg-white/10 p-7 backdrop-blur"><Icon className="h-10 w-10 text-[#f6a800]" /><h3 className="mt-5 text-xl font-black capitalize">{item.title}</h3><p className="mt-3 text-sm leading-7 text-slate-200">{item.text}</p></article>; })}</div></div></section>; }

function News({ news }: { news: NewsPost[] }) { if (!news.length) return null; return <section id="news" className="bg-white px-4 py-16 sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto max-w-7xl"><SectionTitle eyebrow="Latest news" title="Company updates" description="Follow logistics insights, operating updates and company announcements from Galilea Global Logistics." /><div className="mt-10 grid grid-cols-1 gap-6 md:grid-cols-3">{news.slice(0, 3).map((post) => <article key={post.id} className="rounded-md border border-slate-200 bg-[#f5f7fa] p-6"><span className="rounded-md bg-[#f6a800] px-3 py-1 text-xs font-black capitalize text-[#123b68]">{post.category}</span><h3 className="mt-5 text-xl font-black capitalize leading-tight text-[#123b68]">{post.title}</h3><p className="mt-3 text-sm leading-7 text-slate-600">{post.excerpt}</p></article>)}</div></div></section>; }

function Testimonials({ testimonials }: { testimonials: Testimonial[] }) { if (!testimonials.length) return null; return <section className="bg-[#f5f7fa] px-4 py-16 sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto max-w-7xl"><SectionTitle eyebrow="Testimonials" title="What clients say" description="Consistent service, clear communication and dependable cargo execution." /><div className="mt-10 grid gap-6 md:grid-cols-3">{testimonials.slice(0, 3).map((testimonial) => <article key={testimonial.id} className="border-t-4 border-[#f6a800] bg-white p-7 shadow-sm"><div className="flex gap-1 text-[#f6a800]" aria-label={`${testimonial.rating} star rating`}>{Array.from({ length: testimonial.rating }).map((_, index) => <Star key={index} className="h-4 w-4 fill-current" />)}</div><p className="mt-5 text-sm leading-7 text-slate-600">“{testimonial.quote}”</p><p className="mt-5 font-black text-[#123b68]">{testimonial.client_name}</p><p className="text-sm font-semibold text-slate-500">{testimonial.company}</p></article>)}</div></div></section>; }

function NewsletterSignup() {
  const [form, setForm] = useState<NewsletterSubscriberCreate>({ email: "", full_name: "", source: "website" });
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
  async function submit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setStatus("loading");
    try {
      await contentApi.subscribeNewsletter(form);
      setForm({ email: "", full_name: "", source: "website" });
      setStatus("success");
    } catch {
      setStatus("error");
    }
  }
  return <section className="bg-[#123b68] px-4 py-12 text-white sm:px-6 lg:px-8"><div className="mx-auto grid max-w-7xl gap-6 rounded-md border border-white/15 bg-white/10 p-6 backdrop-blur md:grid-cols-[1fr_1.25fr] md:items-center"><div><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">Newsletter</p><h2 className="mt-2 text-3xl font-black capitalize">Logistics alerts and trade updates</h2><p className="mt-3 text-sm leading-7 text-slate-200">Receive practical shipping, customs, and transport updates from the Galilea operations team.</p></div><form onSubmit={submit} className="grid gap-3 sm:grid-cols-[1fr_1fr_auto]"><label className="sr-only" htmlFor="newsletter-name">Full name</label><input id="newsletter-name" value={form.full_name ?? ""} onChange={(event) => setForm({ ...form, full_name: event.target.value })} placeholder="Name or company" className="h-12 rounded-md border border-white/20 bg-white px-4 text-sm font-semibold text-[#123b68] outline-none focus:ring-2 focus:ring-[#f6a800]" /><label className="sr-only" htmlFor="newsletter-email">Email address</label><input id="newsletter-email" type="email" required value={form.email} onChange={(event) => setForm({ ...form, email: event.target.value })} placeholder="Email address" className="h-12 rounded-md border border-white/20 bg-white px-4 text-sm font-semibold text-[#123b68] outline-none focus:ring-2 focus:ring-[#f6a800]" /><Button disabled={status === "loading"} className="h-12 rounded-md bg-[#f6a800] px-6 font-black capitalize text-[#123b68] hover:bg-[#ffc33d]">{status === "loading" ? "Joining" : "Subscribe"}</Button><div className="sm:col-span-3">{status === "success" ? <p className="text-sm font-bold text-[#ffd56f]">Subscription saved successfully.</p> : null}{status === "error" ? <p className="text-sm font-bold text-red-100">Unable to subscribe right now.</p> : null}</div></form></div></section>;
}

function Contact({ settings, services }: { settings: Record<string, string>; services: Service[] }) {
  const [form, setForm] = useState<InquiryCreate>({ full_name: "", email: "", phone: "", company: "", service_interest: services[0]?.title ?? "General logistics", message: "" });
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
  function setField(field: keyof InquiryCreate, value: string) { setForm((current) => ({ ...current, [field]: value })); }
  async function submit(event: FormEvent<HTMLFormElement>) { event.preventDefault(); setStatus("loading"); try { await contentApi.createInquiry(form); setForm({ full_name: "", email: "", phone: "", company: "", service_interest: services[0]?.title ?? "General logistics", message: "" }); setStatus("success"); } catch { setStatus("error"); } }
  return <section id="contact" className="bg-white px-4 py-16 sm:px-6 lg:px-8 lg:py-24"><div className="mx-auto grid max-w-7xl gap-8 lg:grid-cols-[0.82fr_1.18fr]"><div className="rounded-md bg-[#123b68] p-8 text-white"><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">Contact us</p><h2 className="mt-3 text-4xl font-black capitalize">Request a quote today</h2><p className="mt-4 text-base leading-8 text-slate-200">Send us your shipment details and our team will help with route planning, documentation and transport options.</p><div className="mt-8 space-y-5 text-sm font-semibold"><div className="flex gap-3"><Phone className="h-5 w-5 text-[#f6a800]" /><span>{settings.phone}</span></div><div className="flex gap-3"><Mail className="h-5 w-5 text-[#f6a800]" /><span>{settings.email}</span></div><div className="flex gap-3"><MapPin className="h-5 w-5 text-[#f6a800]" /><span>{settings.address}</span></div></div></div><form onSubmit={submit} className="rounded-md border border-slate-200 bg-[#f5f7fa] p-6 shadow-sm sm:p-8"><div className="grid gap-4 sm:grid-cols-2"><Field label="Full name" value={form.full_name} onChange={(value) => setField("full_name", value)} required /><Field label="Email" type="email" value={form.email} onChange={(value) => setField("email", value)} required /><Field label="Phone" value={form.phone ?? ""} onChange={(value) => setField("phone", value)} /><Field label="Company" value={form.company ?? ""} onChange={(value) => setField("company", value)} /></div><label className="mt-4 block text-sm font-black capitalize text-[#123b68]">Service interest<select value={form.service_interest} onChange={(event) => setField("service_interest", event.target.value)} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-sm font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-[#f6a800]">{services.map((service) => <option key={service.id}>{service.title}</option>)}</select></label><label className="mt-4 block text-sm font-black capitalize text-[#123b68]">Shipment details<textarea required value={form.message} onChange={(event) => setField("message", event.target.value)} rows={5} className="mt-2 w-full rounded-md border border-slate-300 bg-white px-4 py-3 text-sm text-slate-700 outline-none focus:ring-2 focus:ring-[#f6a800]" /></label><div className="mt-5 flex flex-col gap-3 sm:flex-row sm:items-center"><Button disabled={status === "loading"} className="h-12 rounded-md bg-[#f6a800] px-7 font-black capitalize text-[#123b68] hover:bg-[#ffc33d]">{status === "loading" ? "Sending..." : "Submit inquiry"}</Button>{status === "success" ? <p className="text-sm font-bold text-emerald-700">Inquiry sent successfully.</p> : null}{status === "error" ? <p className="text-sm font-bold text-red-700">Unable to send inquiry right now.</p> : null}</div></form></div></section>;
}
function Field({ label, value, onChange, type = "text", required = false }: { label: string; value: string; onChange: (value: string) => void; type?: string; required?: boolean }) { return <label className="block text-sm font-black capitalize text-[#123b68]">{label}<input required={required} type={type} value={value} onChange={(event) => onChange(event.target.value)} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-sm font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-[#f6a800]" /></label>; }

function AdminLogin({ onLogin }: { onLogin: () => void }) {
  const [username, setUsername] = useState("admin");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  async function submit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setLoading(true);
    setError("");
    try {
      const response = await adminApi.login({ username, password });
      setAdminToken(response.token);
      sessionStorage.setItem("galilea_admin_unlocked", "true");
      onLogin();
    } catch {
      clearAdminToken();
      setError("Incorrect username or password. Please try again.");
    } finally {
      setLoading(false);
    }
  }
  return <section className="flex min-h-screen items-center justify-center bg-[#0f2f57] px-4 py-12"><div className="w-full max-w-md rounded-md border-t-8 border-[#f6a800] bg-white p-6 shadow-2xl sm:p-8"><img src="/logo.jpeg" alt="Galilea Global Logistics logo" className="h-16 w-16 rounded-md object-cover shadow-sm" /><div className="mt-6 flex items-center gap-3 text-[#123b68]"><span className="flex h-11 w-11 items-center justify-center rounded-md bg-[#fff4d6]"><LockKeyhole className="h-5 w-5" /></span><div><p className="text-sm font-black capitalize tracking-[0.16em] text-[#f6a800]">Admin access</p><h1 className="text-2xl font-black">Dashboard login</h1></div></div><p className="mt-4 text-sm leading-6 text-slate-600">Enter your username and password to manage website content, shipment references, users and delegated page access.</p><form onSubmit={submit} className="mt-6 space-y-4"><label htmlFor="admin-username" className="block text-sm font-black capitalize text-[#123b68]">Username<input id="admin-username" value={username} onChange={(event) => { setUsername(event.target.value); setError(""); }} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-base font-semibold text-[#123b68] outline-none focus:border-[#f6a800] focus:ring-2 focus:ring-[#f6a800]/40" autoComplete="username" required /></label><label htmlFor="admin-password" className="block text-sm font-black capitalize text-[#123b68]">Password<input id="admin-password" type="password" value={password} onChange={(event) => { setPassword(event.target.value); setError(""); }} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-base font-semibold text-[#123b68] outline-none focus:border-[#f6a800] focus:ring-2 focus:ring-[#f6a800]/40" autoComplete="current-password" required /></label>{error ? <p className="rounded-md bg-red-50 px-3 py-2 text-sm font-bold text-red-700">{error}</p> : null}<Button disabled={loading} className="h-12 w-full rounded-md bg-[#123b68] font-black capitalize text-white hover:bg-[#0f2f57] disabled:opacity-70">{loading ? "Checking access" : "Unlock dashboard"}</Button></form><a href="/" className="mt-4 inline-flex min-h-11 items-center text-sm font-black capitalize text-[#123b68] hover:text-[#f6a800]">Return to public website</a></div></section>;
}

function Admin({ data, onDataRefresh }: { data: PublicSitePayload; onDataRefresh: () => Promise<void> }) {
  const [authenticated, setAuthenticated] = useState(() => sessionStorage.getItem("galilea_admin_unlocked") === "true" && Boolean(getAdminToken())); const [tab, setTab] = useState<AdminTab>("overview"); const [collection, setCollection] = useState<AdminCollection>("services"); const [selectedId, setSelectedId] = useState<number | null>(data.services[0]?.id ?? null); const [draft, setDraft] = useState<Record<string, unknown>>({}); const [stats, setStats] = useState<DashboardStats>(defaultStats); const [inquiries, setInquiries] = useState<Inquiry[]>([]); const [settingsRecords, setSettingsRecords] = useState<SiteSetting[]>([]); const [shipments, setShipments] = useState<Shipment[]>([]); const [newsletter, setNewsletter] = useState<NewsletterSubscriber[]>([]); const [users, setUsers] = useState<AdminUser[]>([]); const [saving, setSaving] = useState(false); const [message, setMessage] = useState("");
  const records = useMemo(() => ({ services: data.services, news: data.news, testimonials: data.testimonials, team: data.team, pages: data.dashboard_pages, settings: settingsRecords, inquiries }[collection] as Array<EditableRecord | Inquiry>), [collection, data, inquiries, settingsRecords]);
  const selectedRecord = records.find((record) => record.id === selectedId) ?? records[0] ?? null;
  useEffect(() => { if (!authenticated) return; void Promise.all([adminApi.getStats().then(setStats).catch(() => setStats(defaultStats)), adminApi.getInquiries().then(setInquiries).catch(() => setInquiries([])), adminApi.getSettings().then(setSettingsRecords).catch(() => setSettingsRecords([])), adminApi.getShipments().then(setShipments).catch(() => setShipments([])), adminApi.getNewsletter().then(setNewsletter).catch(() => setNewsletter([])), adminApi.getUsers().then(setUsers).catch(() => setUsers([]))]); }, [authenticated, data]);
  useEffect(() => { setSelectedId(records[0]?.id ?? null); }, [collection, records]);
  useEffect(() => { setDraft(selectedRecord ? { ...selectedRecord } : {}); }, [selectedRecord]);
  async function save() { if (!selectedRecord) return; setSaving(true); setMessage(""); const payload = fields[collection].reduce<Record<string, unknown>>((out, field) => { out[field.key] = draft[field.key]; return out; }, {}); if (collection === "services") { payload.image_object_key = draft.image_object_key ?? null; payload.image_original_filename = draft.image_original_filename ?? null; } try { await adminApi.update(collection, selectedRecord.id, payload); await onDataRefresh(); if (collection === "inquiries") setInquiries(await adminApi.getInquiries()); if (collection === "settings") setSettingsRecords(await adminApi.getSettings()); setMessage("Saved successfully."); } catch { setMessage("Unable to save changes."); } finally { setSaving(false); } }
  function logout() { sessionStorage.removeItem("galilea_admin_unlocked"); clearAdminToken(); setAuthenticated(false); }
  const tabs: Array<{ id: AdminTab; label: string; icon: IconComponent }> = [{ id: "overview", label: "Overview", icon: BarChart3 }, { id: "content", label: "Content updates", icon: FileText }, { id: "shipments", label: "Shipments", icon: Truck }, { id: "newsletter", label: "Newsletter", icon: Mail }, { id: "users", label: "Users & delegation", icon: Users }, { id: "inquiries", label: "Inquiries", icon: Mail }, { id: "workspace", label: "Workspace", icon: LayoutDashboard }];
  if (!authenticated) return <AdminLogin onLogin={() => setAuthenticated(true)} />;
  return <section className="min-h-screen bg-[#f7f6f3]"><div className="flex min-h-screen flex-col lg:flex-row"><aside className="border-b border-slate-200 bg-white lg:w-72 lg:border-r"><div className="p-4"><div className="rounded-md bg-[#123b68] p-4 text-white"><div className="flex items-center gap-3"><LayoutDashboard className="h-5 w-5 text-[#f6a800]" /><div><p className="text-sm font-black">Admin workspace</p><p className="text-xs text-slate-300">Content management desk</p></div></div></div><nav className="mt-4 grid grid-cols-2 gap-2 lg:grid-cols-1">{tabs.map((item) => { const Icon = item.icon; return <button key={item.id} type="button" onClick={() => setTab(item.id)} className={`flex min-h-11 items-center gap-3 rounded-md px-3 py-2 text-left text-sm font-bold ${tab === item.id ? "bg-[#fff4d6] text-[#123b68]" : "text-slate-600 hover:bg-slate-100"}`}><Icon className="h-4 w-4" />{item.label}</button>; })}</nav><button type="button" onClick={logout} className="mt-4 flex min-h-11 w-full items-center gap-3 rounded-md border border-slate-200 px-3 py-2 text-left text-sm font-bold text-slate-600 hover:bg-slate-100"><LogOut className="h-4 w-4" />Log out</button></div></aside><main className="min-w-0 flex-1 p-4 sm:p-6 lg:p-8"><div className="mx-auto max-w-7xl"><div className="flex flex-col justify-between gap-4 border-b border-slate-200 pb-6 lg:flex-row lg:items-end"><div><p className="text-sm font-black capitalize tracking-[0.18em] text-[#f6a800]">Galilea CMS</p><h1 className="mt-2 text-3xl font-black text-[#123b68] sm:text-5xl">Company website dashboard</h1></div><Button onClick={() => void onDataRefresh()} variant="outline" className="h-11 rounded-md">Refresh public content</Button></div>{tab === "overview" ? <Overview stats={stats} data={data} /> : null}{tab === "content" ? <Editor collection={collection} setCollection={setCollection} records={records} selectedRecord={selectedRecord} setSelectedId={setSelectedId} draft={draft} setDraft={setDraft} save={save} saving={saving} message={message} /> : null}{tab === "shipments" ? <ShipmentAdmin shipments={shipments} setShipments={setShipments} /> : null}{tab === "newsletter" ? <NewsletterAdmin subscribers={newsletter} setSubscribers={setNewsletter} /> : null}{tab === "users" ? <UserAdmin users={users} setUsers={setUsers} pages={data.dashboard_pages} /> : null}{tab === "inquiries" ? <Inquiries inquiries={inquiries} setCollection={setCollection} setTab={setTab} setSelectedId={setSelectedId} /> : null}{tab === "workspace" ? <Workspace pages={data.dashboard_pages} /> : null}</div></main></div></section>;
}
function Overview({ stats, data }: { stats: DashboardStats; data: PublicSitePayload }) { const cards = [{ label: "Services", value: stats.services, icon: Truck }, { label: "Shipments", value: stats.shipments, icon: Package }, { label: "Newsletter", value: stats.newsletter_subscribers, icon: Mail }, { label: "Admin users", value: stats.admin_users, icon: Users }, { label: "Published posts", value: stats.news_posts, icon: FileText }, { label: "New inquiries", value: stats.new_inquiries, icon: Mail }, { label: "Testimonials", value: stats.testimonials, icon: Star }]; return <div className="mt-6 grid gap-4 lg:grid-cols-[1fr_360px]"><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{cards.map((card) => { const Icon = card.icon; return <div key={card.label} className="border border-slate-200 bg-white p-5"><Icon className="h-5 w-5 text-[#f6a800]" /><p className="mt-5 text-3xl font-black text-[#123b68]">{card.value}</p><p className="text-sm font-semibold text-slate-500">{card.label}</p></div>; })}</div><div className="border border-slate-200 bg-white p-5"><h2 className="font-black text-[#123b68]">Public website snapshot</h2><p className="mt-3 text-sm leading-7 text-slate-600">{data.settings.hero_title}</p></div></div>; }
function makeDefaultStages(): ShipmentStage[] { return [{ label: "Documents Checked", description: "Shipment paperwork has been received for review.", completed: false, timestamp: null }, { label: "Customs Clearance", description: "Clearance activity will be updated by operations.", completed: false, timestamp: null }, { label: "Transit Coordination", description: "Transport movement status will appear here.", completed: false, timestamp: null }, { label: "Final Delivery", description: "Delivery confirmation will appear when scheduled.", completed: false, timestamp: null }]; }
function formatStages(stages: ShipmentStage[]): string { return JSON.stringify(stages, null, 2); }
function parseStages(value: string): ShipmentStage[] { const parsed = JSON.parse(value) as ShipmentStage[]; if (!Array.isArray(parsed)) throw new Error("Stages must be an array"); return parsed; }
async function cropImageFile(file: File, position: number): Promise<File> { const image = await new Promise<HTMLImageElement>((resolve, reject) => { const img = new Image(); img.onload = () => resolve(img); img.onerror = reject; img.src = URL.createObjectURL(file); }); const targetWidth = 1200; const targetHeight = 800; const sourceRatio = targetWidth / targetHeight; const sourceWidth = image.naturalWidth; const sourceHeight = image.naturalHeight; let cropWidth = sourceWidth; let cropHeight = sourceWidth / sourceRatio; if (cropHeight > sourceHeight) { cropHeight = sourceHeight; cropWidth = sourceHeight * sourceRatio; } const maxX = sourceWidth - cropWidth; const cropX = Math.max(0, Math.min(maxX, maxX * (position / 100))); const cropY = Math.max(0, (sourceHeight - cropHeight) / 2); const canvas = document.createElement("canvas"); canvas.width = targetWidth; canvas.height = targetHeight; const context = canvas.getContext("2d"); if (!context) throw new Error("Canvas is unavailable"); context.drawImage(image, cropX, cropY, cropWidth, cropHeight, 0, 0, targetWidth, targetHeight); URL.revokeObjectURL(image.src); const blob = await new Promise<Blob>((resolve, reject) => canvas.toBlob((output) => output ? resolve(output) : reject(new Error("Unable to crop image")), file.type || "image/jpeg", 0.9)); return new File([blob], file.name.replace(/(\.[^.]+)?$/, "-cropped.jpg"), { type: file.type || "image/jpeg" }); }
function ImageCropper({ file, onCancel, onApply }: { file: File; onCancel: () => void; onApply: (file: File) => void }) { const [position, setPosition] = useState(50); const previewUrl = useMemo(() => URL.createObjectURL(file), [file]); useEffect(() => () => URL.revokeObjectURL(previewUrl), [previewUrl]); async function apply() { const cropped = await cropImageFile(file, position); onApply(cropped); } return <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/70 px-4 py-6"><div className="w-full max-w-2xl rounded-md bg-white p-5 shadow-2xl"><div className="flex items-start justify-between gap-4"><div><p className="text-sm font-black text-[#f6a800]">Crop service image</p><h2 className="text-2xl font-black text-[#123b68]">Keep every card at 3:2</h2><p className="mt-1 text-sm text-slate-600">Move the crop focus before upload. The saved file uses a consistent service-card layout.</p></div><button type="button" onClick={onCancel} className="flex h-11 w-11 items-center justify-center rounded-md border" aria-label="Close cropper"><X className="h-5 w-5" /></button></div><div className="mt-4 overflow-hidden rounded-md bg-slate-100"><img src={previewUrl} alt="Crop preview" className="h-72 w-full object-cover" style={{ objectPosition: `${position}% center` }} /></div><label className="mt-4 block text-sm font-black text-[#123b68]">Horizontal crop focus<input type="range" min="0" max="100" value={position} onChange={(event) => setPosition(Number(event.target.value))} className="mt-2 w-full accent-[#f6a800]" /></label><div className="mt-5 flex flex-col gap-3 sm:flex-row sm:justify-end"><Button type="button" variant="outline" onClick={onCancel} className="h-11 rounded-md">Cancel</Button><Button type="button" onClick={() => void apply()} className="h-11 rounded-md bg-[#123b68]">Crop and use image</Button></div></div></div>; }

function Editor({ collection, setCollection, records, selectedRecord, setSelectedId, draft, setDraft, save, saving, message }: { collection: AdminCollection; setCollection: (collection: AdminCollection) => void; records: Array<EditableRecord | Inquiry>; selectedRecord: EditableRecord | Inquiry | null; setSelectedId: (id: number) => void; draft: Record<string, unknown>; setDraft: (draft: Record<string, unknown>) => void; save: () => Promise<void>; saving: boolean; message: string }) {
  const [uploading, setUploading] = useState(false);
  const [uploadMessage, setUploadMessage] = useState("");
  const [cropFile, setCropFile] = useState<File | null>(null);
  const cols: Array<{ id: AdminCollection; label: string }> = [{ id: "settings", label: "Site settings" }, { id: "services", label: "Services" }, { id: "news", label: "News" }, { id: "testimonials", label: "Testimonials" }, { id: "team", label: "Team" }, { id: "pages", label: "Workspace pages" }, { id: "inquiries", label: "Inquiry status" }];
  async function uploadServiceImage(file: File) {
    if (!file.type.startsWith("image/")) { setUploadMessage("Please choose an image file."); return; }
    if (file.size > 5 * 1024 * 1024) { setUploadMessage("Please choose an image under 5 MB."); return; }
    setUploading(true);
    setUploadMessage("");
    try {
      const contract = await uploadApi.presign({ filename: file.name, content_type: file.type, category: "service-card-images" });
      await uploadApi.uploadFile(contract, file);
      setDraft({ ...draft, image_url: contract.public_url ?? "", image_object_key: contract.object_key, image_original_filename: contract.original_filename });
      setUploadMessage("Image uploaded. Save changes to publish it on the service card.");
    } catch {
      setUploadMessage("Unable to upload image right now.");
    } finally {
      setUploading(false);
    }
  }
  return <><div className="mt-6 grid gap-4 lg:grid-cols-[340px_1fr]"><div className="rounded-md border border-slate-200 bg-white p-4"><p className="text-sm font-black capitalize tracking-[0.12em] text-[#f6a800]">Content update management</p><label className="mt-4 block text-sm font-black capitalize text-[#123b68]">Choose a menu<select value={collection} onChange={(event) => { setCollection(event.target.value as AdminCollection); setUploadMessage(""); }} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-[#f6a800]">{cols.map((item) => <option key={item.id} value={item.id}>{item.label}</option>)}</select></label><label className="mt-4 block text-sm font-black capitalize text-[#123b68]">Choose one item<select value={selectedRecord?.id ?? ""} onChange={(event) => { setSelectedId(Number(event.target.value)); setUploadMessage(""); }} className="mt-2 h-12 w-full rounded-md border border-slate-300 bg-white px-4 text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-[#f6a800]" disabled={!records.length}>{records.map((record) => <option key={record.id} value={record.id}>{titleOf(record)}</option>)}</select></label>{selectedRecord ? <div className="mt-5 rounded-md bg-[#fff4d6] p-4"><p className="text-sm font-black text-[#123b68]">{titleOf(selectedRecord)}</p><p className="mt-1 line-clamp-3 text-xs leading-5 text-slate-600">{descOf(selectedRecord)}</p></div> : <p className="mt-5 rounded-md bg-slate-50 p-4 text-sm font-semibold text-slate-500">No content item is available for this menu yet.</p>}</div><div className="rounded-md border border-slate-200 bg-white p-5">{selectedRecord ? <><div className="mb-5 flex flex-col justify-between gap-3 border-b pb-4 sm:flex-row sm:items-center"><div><p className="text-xs font-black capitalize tracking-[0.14em] text-[#f6a800]">Editing {cols.find((item) => item.id === collection)?.label}</p><h2 className="mt-1 text-2xl font-black text-[#123b68]">{titleOf(selectedRecord)}</h2></div><Button disabled={saving || uploading} onClick={() => void save()} className="h-11 rounded-md bg-[#123b68]"><Save className="mr-2 h-4 w-4" />{saving ? "Saving" : "Save changes"}</Button></div>{collection === "services" ? <div className="mb-5 grid gap-4 rounded-md border border-slate-200 bg-slate-50 p-4 sm:grid-cols-[180px_1fr]"><div className="h-32 overflow-hidden rounded-md bg-white"><img src={String(draft.image_url || serviceImageFor(selectedRecord as Service))} alt="Current service card" className="h-full w-full object-cover" /></div><div><p className="text-sm font-black capitalize text-[#123b68]">Service card image</p><p className="mt-1 text-sm leading-6 text-slate-600">Upload a dedicated logistics image for this service. The file is stored through the runtime upload flow and only the public URL and object metadata are saved.</p><label className="mt-3 inline-flex min-h-11 cursor-pointer items-center rounded-md border border-[#123b68] px-4 text-sm font-black capitalize text-[#123b68] hover:bg-white"><input type="file" accept="image/*" className="sr-only" disabled={uploading} onChange={(event) => { const file = event.target.files?.[0]; if (file) setCropFile(file); event.target.value = ""; }} />{uploading ? "Uploading image" : "Choose and crop image"}</label>{draft.image_original_filename ? <p className="mt-2 text-xs font-bold text-slate-500">Selected: {String(draft.image_original_filename)}</p> : null}{uploadMessage ? <p className="mt-2 rounded-md bg-white px-3 py-2 text-sm font-bold text-[#123b68]">{uploadMessage}</p> : null}</div></div> : null}<div className="grid gap-4">{fields[collection].map((field) => <EditInput key={field.key} field={field} value={draft[field.key]} onChange={(value) => setDraft({ ...draft, [field.key]: value })} />)}</div>{message ? <p className="mt-4 rounded-md bg-slate-50 px-3 py-2 text-sm font-bold text-[#123b68]">{message}</p> : null}</> : <p>Select a menu and item to edit.</p>}</div></div>{cropFile ? <ImageCropper file={cropFile} onCancel={() => setCropFile(null)} onApply={(file) => { setCropFile(null); void uploadServiceImage(file); }} /> : null}</>;
}
function EditInput({ field, value, onChange }: { field: EditableField; value: unknown; onChange: (value: string | number | boolean) => void }) { if (field.type === "checkbox") return <label className="flex min-h-11 items-center gap-3 rounded-md border border-slate-300 px-4 text-sm font-bold text-slate-700"><input type="checkbox" checked={Boolean(value)} onChange={(event) => onChange(event.target.checked)} className="h-5 w-5 accent-[#f6a800]" />{field.label}</label>; if (field.type === "textarea") return <label className="block text-sm font-bold text-slate-700">{field.label}<textarea value={String(value ?? "")} onChange={(event) => onChange(event.target.value)} rows={5} className="mt-2 w-full rounded-md border border-slate-300 px-4 py-3 outline-none focus:ring-2 focus:ring-[#f6a800]" /></label>; return <label className="block text-sm font-bold text-slate-700">{field.label}<input type={field.type} value={String(value ?? "")} onChange={(event) => onChange(field.type === "number" ? Number(event.target.value) : event.target.value)} className="mt-2 h-12 w-full rounded-md border border-slate-300 px-4 outline-none focus:ring-2 focus:ring-[#f6a800]" /></label>; }
function ShipmentAdmin({ shipments, setShipments }: { shipments: Shipment[]; setShipments: (items: Shipment[]) => void }) { const [selectedId, setSelectedId] = useState<number | "new">(shipments[0]?.id ?? "new"); const selected = shipments.find((item) => item.id === selectedId); const [draft, setDraft] = useState<Record<string, string>>({}); const [message, setMessage] = useState(""); useEffect(() => { const item = shipments.find((entry) => entry.id === selectedId); setDraft(item ? { reference_number: item.reference_number, customer_name: item.customer_name, route: item.route, current_stage: item.current_stage, status: item.status, stages: formatStages(item.stages) } : { reference_number: "", customer_name: "", route: "", current_stage: "Documents Checked", status: "In Transit", stages: formatStages(makeDefaultStages()) }); }, [selectedId, shipments]); async function save() { setMessage(""); try { const payload = { reference_number: draft.reference_number, customer_name: draft.customer_name, route: draft.route, current_stage: draft.current_stage, status: draft.status, stages: parseStages(draft.stages) }; if (selected) await adminApi.update<Shipment>("shipments" as AdminCollection, selected.id, payload); else await adminApi.create<Shipment>("shipments" as AdminCollection, payload); setShipments(await adminApi.getShipments()); setMessage("Shipment reference saved."); } catch { setMessage("Check the shipment fields and stage JSON, then try again."); } } async function remove(id: number) { await adminApi.delete("shipments", id); setShipments(await adminApi.getShipments()); setSelectedId("new"); } return <div className="mt-6 grid gap-4 lg:grid-cols-[320px_1fr]"><div className="rounded-md border bg-white p-4"><div className="flex items-center justify-between"><h2 className="font-black text-[#123b68]">Shipment references</h2><button type="button" onClick={() => setSelectedId("new")} className="flex h-10 items-center gap-2 rounded-md bg-[#123b68] px-3 text-sm font-bold text-white"><Plus className="h-4 w-4" />New</button></div><div className="mt-4 space-y-2">{shipments.map((shipment) => <button key={shipment.id} type="button" onClick={() => setSelectedId(shipment.id)} className={`w-full rounded-md border p-3 text-left ${selectedId === shipment.id ? "border-[#f6a800] bg-[#fff4d6]" : "border-slate-200 hover:bg-slate-50"}`}><p className="font-black text-[#123b68]">{shipment.reference_number}</p><p className="text-xs text-slate-500">{shipment.status}</p></button>)}</div></div><div className="rounded-md border bg-white p-5"><div className="grid gap-4 md:grid-cols-2"><Field label="Reference number" value={draft.reference_number ?? ""} onChange={(value) => setDraft({ ...draft, reference_number: value.toUpperCase() })} required /><Field label="Customer name" value={draft.customer_name ?? ""} onChange={(value) => setDraft({ ...draft, customer_name: value })} required /><Field label="Route" value={draft.route ?? ""} onChange={(value) => setDraft({ ...draft, route: value })} required /><Field label="Current stage" value={draft.current_stage ?? ""} onChange={(value) => setDraft({ ...draft, current_stage: value })} required /><Field label="Status" value={draft.status ?? ""} onChange={(value) => setDraft({ ...draft, status: value })} required /></div><label className="mt-4 block text-sm font-black text-[#123b68]">Stage progress JSON<textarea value={draft.stages ?? ""} onChange={(event) => setDraft({ ...draft, stages: event.target.value })} rows={10} className="mt-2 w-full rounded-md border border-slate-300 px-4 py-3 font-mono text-xs outline-none focus:ring-2 focus:ring-[#f6a800]" /></label><div className="mt-4 flex flex-wrap gap-3"><Button onClick={() => void save()} className="h-11 rounded-md bg-[#123b68]">Save shipment</Button>{selected ? <Button variant="outline" onClick={() => void remove(selected.id)} className="h-11 rounded-md text-red-700"><Trash2 className="mr-2 h-4 w-4" />Delete</Button> : null}</div>{message ? <p className="mt-3 rounded-md bg-slate-50 p-3 text-sm font-bold text-[#123b68]">{message}</p> : null}</div></div>; }
function NewsletterAdmin({ subscribers, setSubscribers }: { subscribers: NewsletterSubscriber[]; setSubscribers: (items: NewsletterSubscriber[]) => void }) { async function toggle(item: NewsletterSubscriber) { await adminApi.update<NewsletterSubscriber>("newsletter" as AdminCollection, item.id, { is_active: !item.is_active }); setSubscribers(await adminApi.getNewsletter()); } async function remove(id: number) { await adminApi.delete("newsletter", id); setSubscribers(await adminApi.getNewsletter()); } return <div className="mt-6 rounded-md border bg-white"><div className="border-b p-5"><h2 className="text-2xl font-black text-[#123b68]">Newsletter subscribers</h2><p className="mt-1 text-sm text-slate-600">Manage public newsletter signups and active subscription status.</p></div>{subscribers.map((item) => <div key={item.id} className="grid gap-3 border-b p-4 md:grid-cols-[1fr_150px_170px]"><div><p className="font-black text-[#123b68]">{item.email}</p><p className="text-sm text-slate-500">{item.full_name || "No name"} • {item.source}</p></div><span className={`w-fit rounded-full px-3 py-1 text-xs font-black ${item.is_active ? "bg-emerald-100 text-emerald-800" : "bg-slate-100 text-slate-500"}`}>{item.is_active ? "Active" : "Paused"}</span><div className="flex gap-2"><Button variant="outline" onClick={() => void toggle(item)} className="h-10 rounded-md">{item.is_active ? "Pause" : "Activate"}</Button><Button variant="outline" onClick={() => void remove(item.id)} className="h-10 rounded-md text-red-700"><Trash2 className="h-4 w-4" /></Button></div></div>)}</div>; }
function UserAdmin({ users, setUsers, pages }: { users: AdminUser[]; setUsers: (items: AdminUser[]) => void; pages: DashboardPage[] }) { const [draft, setDraft] = useState({ username: "", full_name: "", password: "", role: "editor", delegated_pages: [] as string[], is_active: true }); const [message, setMessage] = useState(""); async function createUser() { setMessage(""); try { await adminApi.create<AdminUser>("users" as AdminCollection, draft); setUsers(await adminApi.getUsers()); setDraft({ username: "", full_name: "", password: "", role: "editor", delegated_pages: [], is_active: true }); setMessage("Admin user created with delegated page access."); } catch { setMessage("Unable to create user. Check username uniqueness and password length."); } } async function updateUser(user: AdminUser, updates: Record<string, unknown>) { await adminApi.update<AdminUser>("users" as AdminCollection, user.id, updates); setUsers(await adminApi.getUsers()); } return <div className="mt-6 grid gap-4 xl:grid-cols-[1fr_380px]"><div className="rounded-md border bg-white p-5"><h2 className="text-2xl font-black text-[#123b68]">User management and delegation</h2><div className="mt-4 space-y-3">{users.map((user) => <div key={user.id} className="rounded-md border border-slate-200 p-4"><div className="flex flex-col justify-between gap-3 sm:flex-row"><div><p className="font-black text-[#123b68]">{user.full_name}</p><p className="text-sm text-slate-500">{user.username} • {user.role}</p></div><label className="flex items-center gap-2 text-sm font-bold"><input type="checkbox" checked={user.is_active} onChange={(event) => void updateUser(user, { is_active: event.target.checked })} className="h-5 w-5 accent-[#f6a800]" />Active</label></div><div className="mt-3 flex flex-wrap gap-2">{pages.map((page) => { const checked = user.delegated_pages.includes(page.slug) || user.delegated_pages.includes(page.title.toLowerCase()); return <label key={page.id} className="rounded-full border px-3 py-1 text-xs font-bold"><input type="checkbox" checked={checked} onChange={(event) => { const next = event.target.checked ? [...user.delegated_pages, page.slug] : user.delegated_pages.filter((slug) => slug !== page.slug); void updateUser(user, { delegated_pages: next }); }} className="mr-2 accent-[#f6a800]" />{page.title}</label>; })}</div></div>)}</div></div><div className="rounded-md border bg-white p-5"><h3 className="font-black text-[#123b68]">Create admin user</h3><div className="mt-4 space-y-3"><Field label="Username" value={draft.username} onChange={(value) => setDraft({ ...draft, username: value })} required /><Field label="Full name" value={draft.full_name} onChange={(value) => setDraft({ ...draft, full_name: value })} required /><Field label="Temporary password" type="password" value={draft.password} onChange={(value) => setDraft({ ...draft, password: value })} required /><Field label="Role" value={draft.role} onChange={(value) => setDraft({ ...draft, role: value })} required /><Button onClick={() => void createUser()} className="h-11 w-full rounded-md bg-[#123b68]">Create user</Button>{message ? <p className="rounded-md bg-slate-50 p-3 text-sm font-bold text-[#123b68]">{message}</p> : null}</div></div></div>; }
function Inquiries({ inquiries, setCollection, setTab, setSelectedId }: { inquiries: Inquiry[]; setCollection: (collection: AdminCollection) => void; setTab: (tab: AdminTab) => void; setSelectedId: (id: number) => void }) { return <div className="mt-6 border bg-white">{inquiries.map((inquiry) => <button key={inquiry.id} type="button" onClick={() => { setCollection("inquiries"); setSelectedId(inquiry.id); setTab("content"); }} className="grid w-full gap-2 border-b p-4 text-left hover:bg-slate-50 lg:grid-cols-[1fr_1fr_140px]"><div><p className="font-black text-[#123b68]">{inquiry.full_name}</p><p className="text-sm text-slate-500">{inquiry.email}</p></div><p className="text-sm text-slate-600">{inquiry.service_interest}</p><span className="w-fit bg-[#fff4d6] px-3 py-1 text-xs font-bold text-[#123b68]">{inquiry.status}</span></button>)}</div>; }
function Workspace({ pages }: { pages: DashboardPage[] }) { return <div className="mt-6 grid gap-4 lg:grid-cols-3">{pages.map((page) => <article key={page.id} className="border bg-white p-5"><h2 className="font-black text-[#123b68]">{page.title}</h2><div className="mt-5 space-y-3">{page.blocks.map((block, index) => <p key={`${page.id}-${index}`} className="bg-slate-50 p-3 text-sm">{block.content}</p>)}</div></article>)}</div>; }
function Loading() { return <div className="flex min-h-screen items-center justify-center bg-[#123b68] px-4 text-white"><div className="text-center"><img src="/logo.jpeg" alt="Galilea Global Logistics logo" className="mx-auto h-16 w-16 animate-pulse rounded-md object-cover" /><p className="mt-4 text-lg font-black capitalize">Loading Galilea Global Logistics...</p></div></div>; }

function App() {
  const [mode, setMode] = useState<ViewMode>(() => window.location.pathname === "/admin" ? "admin" : "website");
  const [data, setData] = useState<PublicSitePayload>(fallbackPayload);
  const [loading, setLoading] = useState(true);
  async function loadData() { const payload = await contentApi.getPublicSite(); setData(payload); }
  useEffect(() => { loadData().catch(() => setData(fallbackPayload)).finally(() => setLoading(false)); }, []);
  useEffect(() => {
    const syncModeFromPath = () => setMode(window.location.pathname === "/admin" ? "admin" : "website");
    syncModeFromPath();
    window.addEventListener("popstate", syncModeFromPath);
    return () => window.removeEventListener("popstate", syncModeFromPath);
  }, []);
  if (loading) return <Loading />;
  const services = data.services.length ? data.services : fallbackServices;
  if (mode === "admin") return <Admin data={data} onDataRefresh={loadData} />;
  return <div className="min-h-screen bg-white text-slate-950"><Header mode={mode} settings={data.settings} /><main><Hero settings={data.settings} /><Services services={services} /><About team={data.team} /><WhyChoose /><News news={data.news} /><Testimonials testimonials={data.testimonials} /><NewsletterSignup /><Contact settings={data.settings} services={services} /></main><footer className="bg-[#0f2f57] px-4 py-8 text-center text-sm font-semibold text-slate-200 sm:px-6 lg:px-8">© {new Date().getFullYear()} {data.settings.company_name}. All rights reserved. <span className="text-[#f6a800]">Dynamic website powered by Galilea CMS.</span></footer></div>;
}

export default App;
